+fn auto_bead_id(fingerprint: &str) -> String {
+    let normalized = fingerprint
+        .strip_prefix("sha256:")
+        .unwrap_or(fingerprint)
+        .chars()
+        .take(8)
+        .collect::<String>();
+    format!("bd-auto-{normalized}")
